    def _resolve_dynamic_defaults(self, ctx: Context) -> None:
        """Resolve dict-based dynamic defaults now that every parameter
        has been parsed from the command line, environment variables,
        and configuration files.

        A dynamic default maps the value of one or more other options
        to the default that should be used, e.g.
        ``{"--protocol": {"http": 80, "https": 443}}``. It's only applied
        to options whose value still comes from :attr:`Option.default`
        (i.e. no value was explicitly provided).
        """
        for param in self.get_params(ctx):
            if not isinstance(param, Option) or not isinstance(param.default, dict):
                continue

            if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
                continue

            resolved = None

            for opt_decl, value_map in param.default.items():
